const rawOutput = $input.item.json.output || "";

// Função para limpar o texto em etapas
function cleanAgentOutput(text) {
  if (!text) return "";

  let cleaned = text;

  // 1. Remove blocos de código Markdown (```json ... ```)
  cleaned = cleaned.replace(/```[\s\S]*?```/g, "");

  // 2. Remove metadados entre colchetes [ ... ]
  // Ex: [Pensando...], [Tool_Use: ...]
  cleaned = cleaned.replace(/\[[\s\S]*?\]/g, "");

  // 3. Remove linhas de comando de ferramenta (que começam com /)
  // Ex: /atualizar_kanban {"a": 1}
  // O 'm' no final faz o ^ funcionar para cada linha
  cleaned = cleaned.replace(/^\s*\/[\w_-]+.*$/gm, "");

  // 4. Remove objetos JSON soltos { ... }
  // Isso pega qualquer coisa que pareça um objeto JSON técnico
  cleaned = cleaned.replace(/\{[\s\S]*?\}/g, "");

  // 5. Limpeza final de pontuação "suja"
  // Remove sobras de colchetes ou aspas que podem ter ficado
  cleaned = cleaned.replace(/^[\])}]+/, ""); // Remove ] ou ) ou } no começo

  // 6. Remove excesso de linhas em branco e espaços
  cleaned = cleaned.replace(/\n\s*\n/g, "\n").trim();

  return cleaned;
}

const textoFinal = cleanAgentOutput(rawOutput);

return [
  {
    json: {
      texto_original: rawOutput,
      texto_limpo: textoFinal
    }
  }
];

